<template>
  <div>
    <label class="b-24-black" v-html="t('audio.title')"></label>
    <p></p>
    <!-- <p class="r-16-gray py-4 px-3" v-html="t('audio.saber')">
        </p> -->
    <p class="b-16-black ps-3 text-start" v-html="t('audio.escoje')">
    </p>

    <div v-if="isLoading" class="d-flex justify-content-center pt-5">
      <div class="spinner-border text-secondary" role="status">
        <span class="visually-hidden">Loading...</span>
      </div>
    </div>

    <div v-else class="square-info pt-3 pb-2 px-3">
      <ul class="ps-0">
        <li v-for="item in duraciones" :key="item.IdDuracion" class="list-group-item text-start py-2">
          <input @click="SetConfigUser()" class="form-check-input me-1" type="radio" name="dur"
            :id="`opc-${item.IdDuracion}`" :value="item.IdDuracion" />
          <label :for="`opc-${item.IdDuracion}`">{{ item.Descripcion }}</label>
        </li>
      </ul>
    </div>
    <!-- <p class="r-16-gray py-4 px-3" v-html="t('audio.sugerencia')">
        </p> -->
  </div>

</template>
<script setup>
import { useI18n } from 'vue-i18n'
import { ref, onMounted, nextTick } from 'vue'
import { API_BASE_URL } from '@/config/api'

const { t } = useI18n()

const duraciones = ref([])
const isLoading = ref(true)

async function GetDuraciones() {
  try {
    const response = await fetch(`${API_BASE_URL}/api/config/GetAudioLengths`, {
      method: "POST",
      headers: { "Content-Type": "application/json" }
    })
    const data = await response.json()
    return JSON.parse(data.data);
  } catch (err) {
    console.error('Error al cargar duraciones:', err)
    return [];
  }
}

async function GetConfigUser() {
  const sesion = localStorage.getItem("token")
  if (!sesion) return null;

  try {
    const response = await fetch(`${API_BASE_URL}/api/config/GetAudioLength`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ username: sesion })
    })

    if (!response.ok) throw new Error("Error en la petición")

    const data = await response.json()
    return data.data;

  } catch (err) {
    console.error('Error al cargar configuracion de usuario:', err)
    return null;
  }
}

async function SetConfigUser() {
  const sesion = localStorage.getItem("token")
  if (!sesion) return

  const response = await fetch(`${API_BASE_URL}/api/config/SetAudioLength`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ username: sesion, idAudioLength: document.querySelector('input[name="dur"]:checked').value })
  })

  if (!response.ok) throw new Error("Error en la petición")

  const data = await response.json()
  console.log(data)
}

async function Initialize() {
  isLoading.value = true;

  // Fetch both concurrently to save time
  const [lengthsData, userConfigId] = await Promise.all([
    GetDuraciones(),
    GetConfigUser()
  ]);

  duraciones.value = lengthsData;
  isLoading.value = false;

  if (userConfigId) {
    await nextTick(); // Wait for the v-if="isLoading" to toggle and render the radio buttons
    const optionEl = document.getElementById('opc-' + userConfigId);
    if (optionEl) {
      optionEl.checked = true;
    }
  }
}


onMounted(() => {
  Initialize();
})

</script>